# Cache for `create_cloned_field`
_CLONED_TYPES_CACHE: MutableMapping[
    Type[BaseModel], Type[BaseModel]
] = WeakKeyDictionary()


def is_body_allowed_for_status_code(status_code: Union[int, str, None]) -> bool:
    """Return True if a request body is allowed for the given HTTP status code.

    Accepts numeric status codes or OpenAPI "patterned" status codes such as
    "2XX" or the literal "default". Returns False for status codes that do not
    allow bodies (e.g. 1xx, 204, 304).
    """
    if status_code is None:
        return True
    # Ref: https://github.com/OAI/OpenAPI-Specification/blob/main/versions/3.1.0.md#patterned-fields-1
    if status_code in {
        "default",
        "1XX",
        "2XX",
        "3XX",
        "4XX",
        "5XX",
    }:
        return True
    current_status_code = int(status_code)
    return not (current_status_code < 200 or current_status_code in {204, 304})


def get_path_param_names(path: str) -> Set[str]:
    """Extract and return a set of path parameter names from a FastAPI path string.

    For example, "/items/{item_id}/sub/{sub_id}" -> {"item_id", "sub_id"}.
    """
    return set(re.findall("{(.*?)}", path))


def create_response_field(
    name: str,
    type_: Type[Any],
    class_validators: Optional[Dict[str, Validator]] = None,
    default: Optional[Any] = Undefined,
    required: Union[bool, UndefinedType] = Undefined,
    model_config: Type[BaseConfig] = BaseConfig,
    field_info: Optional[FieldInfo] = None,
    alias: Optional[str] = None,
    mode: Literal["validation", "serialization"] = "validation",
) -> ModelField:
    """
    Create a new response field. Raises if type_ is invalid.
    """
    class_validators = class_validators or {}
    if PYDANTIC_V2:
        field_info = field_info or FieldInfo(
            annotation=type_, default=default, alias=alias
        )
    else:
        field_info = field_info or FieldInfo()
    kwargs = {"name": name, "field_info": field_info}
    if PYDANTIC_V2:
        kwargs.update({"mode": mode})
    else:
        kwargs.update(
            {
                "type_": type_,
                "class_validators": class_validators,
                "default": default,
                "required": required,
                "model_config": model_config,
                "alias": alias,
            }
        )
    try:
        return ModelField(**kwargs)  # type: ignore[arg-type]
    except (RuntimeError, PydanticSchemaGenerationError):
        raise fastapi.exceptions.FastAPIError(
            "Invalid args for response field! Hint: "
            f"check that {type_} is a valid Pydantic field type. "
            "If you are using a return type annotation that is not a valid Pydantic "
            "field (e.g. Union[Response, dict, None]) you can disable generating the "
            "response model from the type annotation with the path operation decorator "
            "parameter response_model=None. Read more: "
            "https://fastapi.tiangolo.com/tutorial/response-model/"
        ) from None


def create_cloned_field(
    field: ModelField,
    *,
    cloned_types: Optional[MutableMapping[Type[BaseModel], Type[BaseModel]]] = None,
) -> ModelField:
    """Return a cloned ModelField suitable for response model generation.

    For Pydantic v2 this is a no-op and the original field is returned. For
    Pydantic v1, when the field's type is a BaseModel (including dataclasses
    converted to pydantic models), a cloned model type is created and cached to
    avoid issues with recursive models and to prevent mutating the original
    model definitions.
    """
    if PYDANTIC_V2:
        return field
    # cloned_types caches already cloned types to support recursive models and improve
    # performance by avoiding unnecessary cloning
    if cloned_types is None:
        cloned_types = _CLONED_TYPES_CACHE

    original_type = field.type_
    if is_dataclass(original_type) and hasattr(original_type, "__pydantic_model__"):
        original_type = original_type.__pydantic_model__
    use_type = original_type
    if lenient_issubclass(original_type, BaseModel):
        original_type = cast(Type[BaseModel], original_type)
        if original_type in cloned_types:
            use_type = cloned_types[original_type]
        else:
            # Build fields dict for create_model
            fields: Dict[str, Any] = {}
            try:
                for name, model_field in original_type.__fields__.items():
                    outer_type = getattr(model_field, "outer_type_", None) or getattr(
                        model_field, "type_", Any
                    )
                    default = model_field.default if not model_field.required else ...
                    fields[name] = (outer_type, default)
            except Exception:
                # Fallback: if introspecting __fields__ fails for some custom model,
                # avoid failing and use the original type instead of cloning.
                cloned_types[original_type] = original_type
                use_type = original_type
            else:
                # Create a new model with the same fields to avoid modifying the original
                try:
                    new_model = create_model(
                        f"{original_type.__name__}__clone", __base__=original_type, **fields
                    )
                    cloned_types[original_type] = new_model
                    use_type = new_model
                except Exception:
                    cloned_types[original_type] = original_type
                    use_type = original_type

    # If no cloning was necessary or succeeded, return a new ModelField preserving
    # the existing metadata but pointing to the chosen type.
    try:
        if PYDANTIC_V2:
            # For v2, we never enter here because returned earlier, but keep for parity.
            return field
        else:
            # Recreate field for pydantic v1
            return create_response_field(
                name=field.name,
                type_=use_type,
                class_validators=getattr(field, "class_validators", None),
                default=getattr(field, "default", Undefined),
                required=getattr(field, "required", Undefined),
                model_config=getattr(field, "model_config", BaseConfig),
                field_info=getattr(field, "field_info", None),
                alias=getattr(field, "alias", None),
            )
    except Exception:
        # As a last resort, return the original field
        return field


def _simplify_path_for_id(path: str) -> str:
    # Helper to sanitize path into a safe operation id fragment.
    path = path.strip("/")
    # Replace common separators and remove braces
    path = re.sub(r"[{}]", "", path)
    path = path.replace("/", "_")
    path = re.sub(r"[^a-zA-Z0-9_]+", "_", path)
    return path.strip("_")


def generate_operation_id_for_path(path: str, method: str) -> str:
    """Generate a reasonable default operation ID for a path and HTTP method.

    The generated ID is a lowercase string combining the HTTP method and a
    sanitized version of the path, suitable for use as an OpenAPI operationId.
    Example: method="GET", path="/items/{item_id}" -> "get_items_item_id"
    """
    method_part = method.lower()
    path_part = _simplify_path_for_id(path)
    if path_part:
        return f"{method_part}_{path_part}"
    return method_part


def generate_unique_id(existing_ids: Set[str], name: str) -> str:
    """Generate a unique identifier based on name that does not collide with existing_ids.

    If `name` is already present in existing_ids, append a counter suffix like
    "_1", "_2", etc., until a unique id is found.
    """
    if name not in existing_ids:
        return name
    i = 1
    while True:
        candidate = f"{name}_{i}"
        if candidate not in existing_ids:
            return candidate
        i += 1


def deep_dict_update(original: Dict[Any, Any], update: Dict[Any, Any]) -> Dict[Any, Any]:
    """Recursively update a dictionary with another dictionary.

    Values in `update` overwrite or are merged into `original`. Nested mappings
    are merged recursively instead of replaced.
    """
    for key, value in update.items():
        if (
            key in original
            and isinstance(original[key], dict)
            and isinstance(value, dict)
        ):
            deep_dict_update(original[key], value)
        else:
            original[key] = value
    return original


def match_pydantic_error_url(error_string: str) -> Optional[str]:
    """Search an error string for a Pydantic issue URL and return it if found.

    The function looks for common Pydantic error message patterns that include a
    link to the Pydantic docs or GitHub and returns the first matching URL,
    or None if none is found.
    """
    # Common patterns include links to pydantic-docs or GitHub issues/releases.
    # We'll search for https URLs that reference 'pydantic' or 'pydantic-docs'.
    match = re.search(r"https?://[^\s)\"']*(?:pydantic|pydantic-docs)[^\s)\"']*", error_string)
    if match:
        return match.group(0)
    return None

